script:
frappe.ui.form.on('Maintenance Request', {
    setup(frm) {
        // Only show equipment belonging to the selected customer.
        frm.set_query('equipment', function () {
            return { filters: { customer: frm.doc.customer || '__none__' } };
        });
    },
    refresh(frm) {
        if (!frm.is_new()
            && frm.doc.workflow_state === 'Signed Off'
            && !frm.doc.sales_invoice) {
            frm.add_custom_button(__('Create Sales Invoice'), function () {
                frappe.call({
                    method: 'gulf_maintenance.api.create_sales_invoice',
                    args: { maintenance_request: frm.doc.name },
                    freeze: true,
                    freeze_message: __('Creating draft Sales Invoice...'),
                    callback: function (r) {
                        if (r.message) {
                            frappe.set_route('Form', 'Sales Invoice', r.message);
                        }
                    }
                });
            }).addClass('btn-primary');
        }
    },
    customer(frm) {
        if (frm.doc.equipment) {
            frm.set_value('equipment', null);
        }
    }
});

function gm_recompute(frm) {
    let total = 0;
    (frm.doc.parts_used || []).forEach(function (row) {
        row.amount = flt(row.qty) * flt(row.rate);
        total += flt(row.amount);
    });
    frm.set_value('total_parts_cost', total);
    frm.refresh_field('parts_used');
}

frappe.ui.form.on('Parts Used', {
    qty: gm_recompute,
    rate: gm_recompute,
    parts_used_remove: gm_recompute
});
